import psycopg2
from psycopg2 import sql, errors

def connect():
    conn = None
    try:
        conn = psycopg2.connect(
            host="localhost",  # replace with your server address if not localhost
            database="myDatabase",  # replace with the name of your database
            user="postgres",  # replace with your username
            password="mypassword"  # replace with your password
        )
    except (Exception, psycopg2.DatabaseError) as error:
        print(error)
    return conn

def search_users(username=None, email=None, role=None, status=None):
    conn = connect()
    cur = conn.cursor()
    
    query = "SELECT * FROM users WHERE 1 = 1"
    if username is not None:
        query += f" AND username LIKE '%{username}%'"
    if email is not None:
        query += f" AND email LIKE '%{email}%'"
    if role is not None:
        query += f" AND role = '{role}'"
    if status is not None:
        query += f" AND account_status = '{status}'"
    
    cur.execute(query)
    
    rows = cur.fetchall()

    for row in rows:
        print(f'Username: {row[1]}, Email: {row[2]}, Role: {row[3]}, Status: {row[4]}') # assuming the user_id, username, email, role and account status are at positions 1 to 4 in your database.
    cur.close()